import { ReactElement } from 'react';
import { Root } from 'react-dom/client';

declare const MARK = "__react_root__";
type ContainerType = (Element | DocumentFragment) & {
    [MARK]?: Root;
};
declare function render(node: ReactElement, container: ContainerType): void;
declare function unmount(container: ContainerType): boolean | Promise<void>;

export { render, unmount };
